import{_ as s,c as a,o as n,a as l}from"./app.204b65b3.js";const e="/note/assets/3.42f158cd.png",p="/note/assets/4.41ad3b42.png",D=JSON.parse('{"title":"git 配置多个 SSH-Key","description":"","frontmatter":{},"headers":[{"level":2,"title":"1.查看 Git 全局设置","slug":"_1-查看-git-全局设置","link":"#_1-查看-git-全局设置","children":[]},{"level":2,"title":"2.生成新的 SSH keys","slug":"_2-生成新的-ssh-keys","link":"#_2-生成新的-ssh-keys","children":[{"level":3,"title":"2.1 生成 GitLab 账号的 SSH-Keys","slug":"_2-1-生成-gitlab-账号的-ssh-keys","link":"#_2-1-生成-gitlab-账号的-ssh-keys","children":[]},{"level":3,"title":"2.2 生成 Github 账号的 SSH-Keys","slug":"_2-2-生成-github-账号的-ssh-keys","link":"#_2-2-生成-github-账号的-ssh-keys","children":[]},{"level":3,"title":"2.3 添加 conig 配置文件","slug":"_2-3-添加-conig-配置文件","link":"#_2-3-添加-conig-配置文件","children":[]},{"level":3,"title":"2.4 配置完，目录中的文件","slug":"_2-4-配置完-目录中的文件","link":"#_2-4-配置完-目录中的文件","children":[]}]},{"level":2,"title":"3. 验证连接 Git","slug":"_3-验证连接-git","link":"#_3-验证连接-git","children":[]},{"level":2,"title":"4. 无法连接问题","slug":"_4-无法连接问题","link":"#_4-无法连接问题","children":[]}],"relativePath":"articles/04-其他/Git/06-git 配置多个SSH-Key.md"}'),o={name:"articles/04-其他/Git/06-git 配置多个SSH-Key.md"},t=l(`<h1 id="git-配置多个-ssh-key" tabindex="-1">git 配置多个 SSH-Key <a class="header-anchor" href="#git-配置多个-ssh-key" aria-hidden="true">#</a></h1><p>一般公司使用 <code>GitLab</code> 搭建的内部私有 <code>Git</code> 仓库，同时自己平时用 <code>github</code> 的账号，存在两个<code>Git</code>，如果直接使用 SSH-Key 会把之前的<code>GitLab</code>的 SSH-Key 覆盖。</p><blockquote><p>有两个 Github 账号，同一台电脑同时连接两个账号进行版本控制。 公司使用 Gitlab 账号，自己使用 Github 账号。</p></blockquote><h2 id="_1-查看-git-全局设置" tabindex="-1">1.查看 Git 全局设置 <a class="header-anchor" href="#_1-查看-git-全局设置" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">config</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--list</span></span>
<span class="line"></span></code></pre></div><p>设置 <code>user.name</code> 和 <code>user.email</code></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">config</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--global</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">user.name</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">your_name</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">config</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--global</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">user.email</span><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">your_email</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span></code></pre></div><p>删除全局设置的方法：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">config</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--global</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--unset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">user.name</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">your_name</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">config</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--global</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--unset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">user.email</span><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">your_email</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span></code></pre></div><h2 id="_2-生成新的-ssh-keys" tabindex="-1">2.生成新的 SSH keys <a class="header-anchor" href="#_2-生成新的-ssh-keys" aria-hidden="true">#</a></h2><p>生成 SSH keys 命令</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">ssh-keygen</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-t</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">rsa</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-C</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">your_email</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span></code></pre></div><h3 id="_2-1-生成-gitlab-账号的-ssh-keys" tabindex="-1">2.1 生成 GitLab 账号的 SSH-Keys <a class="header-anchor" href="#_2-1-生成-gitlab-账号的-ssh-keys" aria-hidden="true">#</a></h3><p>1、用命令在控制台生成私钥和私钥</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 在~/.ssh/目录会生成gitlab_id_rsa和gitlab_id_rsa.pub私钥和公钥。</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 我们将gitlab_id-rsa.pub中的内容粘帖到公司GitLab服务器的SSH-key的配置中。</span></span>
<span class="line"><span style="color:#FFCB6B;">ssh-keygen</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-t</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">rsa</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-C</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">your_email</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-f</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">~/.ssh/gitlab_id_rsa</span></span>
<span class="line"></span></code></pre></div><p>2、在 GitLab 管理面板设置，复制公钥 <code>gitlab_id_rsa.pub</code> 的内容到密钥框。</p><p>可用命令查看，也可以用编辑器查看。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">cat</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">gitlab_id_rsa.pub</span></span>
<span class="line"></span></code></pre></div><p>SSH 密钥设置面板</p><p><img src="`+e+`" alt="img" data-fancybox="gallery"></p><h3 id="_2-2-生成-github-账号的-ssh-keys" tabindex="-1">2.2 生成 Github 账号的 SSH-Keys <a class="header-anchor" href="#_2-2-生成-github-账号的-ssh-keys" aria-hidden="true">#</a></h3><p>1、用命令在控制台生成私钥和私钥</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 在~/.ssh/目录会生成github_id_rsa和github_id_rsa.pub私钥和公钥。</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 我们将github_id_rsa.pub中的内容粘帖到Github的SSH-key的配置中。</span></span>
<span class="line"><span style="color:#FFCB6B;">ssh-keygen</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-t</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">rsa</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-C</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">your_email</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-f</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">~/.ssh/github_id_rsa</span></span>
<span class="line"></span></code></pre></div><p>2、在 Github 管理面板设置，复制公钥 <code>github_id_rsa.pub</code> 的内容到密钥框。</p><p>可用命令查看，也可以用编辑器查看。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">cat</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">github_id_rsa.pub</span></span>
<span class="line"></span></code></pre></div><p>SSH 密钥设置面板</p><p><img src="`+p+`" alt="img" data-fancybox="gallery"></p><h3 id="_2-3-添加-conig-配置文件" tabindex="-1">2.3 添加 conig 配置文件 <a class="header-anchor" href="#_2-3-添加-conig-配置文件" aria-hidden="true">#</a></h3><p>在~/.ssh 目录下添加<code>config</code>配置文件用于区分多个<code>SSH-Key</code></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 添加config配置文件</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># vi ~/.ssh/config</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 文件内容如下：</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># gitlab</span></span>
<span class="line"><span style="color:#FFCB6B;">Host</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">gitlab.com</span></span>
<span class="line"><span style="color:#FFCB6B;">HostName</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">gitlab.com</span></span>
<span class="line"><span style="color:#FFCB6B;">PreferredAuthentications</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">publickey</span></span>
<span class="line"><span style="color:#FFCB6B;">IdentityFile</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">~/.ssh/gitlab_id_rsa</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># github</span></span>
<span class="line"><span style="color:#FFCB6B;">Host</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">github.com</span></span>
<span class="line"><span style="color:#FFCB6B;">HostName</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">github.com</span></span>
<span class="line"><span style="color:#FFCB6B;">PreferredAuthentications</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">publickey</span></span>
<span class="line"><span style="color:#FFCB6B;">IdentityFile</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">~/.ssh/github_id_rsa</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 配置文件参数</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># Host : Host可以看作是一个你要识别的模式，对识别的模式，进行配置对应的的主机名和ssh文件</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># HostName : 要登录主机的主机名</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># User : 登录名</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># IdentityFile : 指明上面User对应的identityFile路径</span></span>
<span class="line"></span></code></pre></div><h3 id="_2-4-配置完-目录中的文件" tabindex="-1">2.4 配置完，目录中的文件 <a class="header-anchor" href="#_2-4-配置完-目录中的文件" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">~/.ssh/</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FFCB6B;">ls</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FFCB6B;">github_id_rsa.pub</span></span>
<span class="line"><span style="color:#FFCB6B;">github_id_rsa</span></span>
<span class="line"><span style="color:#FFCB6B;">gitlab_id_rsa.pub</span></span>
<span class="line"><span style="color:#FFCB6B;">gitlab_id_rsa</span></span>
<span class="line"><span style="color:#FFCB6B;">known_hosts</span></span>
<span class="line"></span></code></pre></div><h2 id="_3-验证连接-git" tabindex="-1">3. 验证连接 Git <a class="header-anchor" href="#_3-验证连接-git" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">ssh</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-T</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">git@github.com</span></span>
<span class="line"></span></code></pre></div><p>如果连接不成功的话，用户命令查看错误信息</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">ssh</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-vT</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">git@gihub.com</span><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">#查看出错信息</span></span>
<span class="line"></span></code></pre></div><h2 id="_4-无法连接问题" tabindex="-1">4. 无法连接问题 <a class="header-anchor" href="#_4-无法连接问题" aria-hidden="true">#</a></h2><p>如果出现</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">Permission</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">denied（Publickey）</span></span>
<span class="line"></span></code></pre></div><p>解决方案：</p><p>以 <code>Github</code> 连接不上为例：</p><p>1、把私钥<code>github_id_rsa</code>，重新添加到<code>ssh_agent</code>，并验证连接</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">ssh-agent</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">bash</span></span>
<span class="line"><span style="color:#FFCB6B;">ssh-add</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">~/.ssh/github_id_rsa</span></span>
<span class="line"></span></code></pre></div><p>2、把公钥<code>github_id_rsa.pub</code>，重新添加到 <code>Git</code> 账号<code>SSH Keys</code>，再验证连接。</p><p>3、最终还是没办法连接成功，重新按上面步骤操作。</p>`,46),c=[t];function i(r,y,C,d,h,b){return n(),a("div",null,c)}const u=s(o,[["render",i]]);export{D as __pageData,u as default};
